/**
 * Unit tests for the agent-usage.jsonl contract changes (#3034, #3035).
 *
 * #3035 — a phantom SubagentStop is the conjunction of three signals: no
 * resolved type, no staged start, no transcript on disk. All three are
 * required; any one alone misclassifies a real agent.
 *
 * #3034 — `agent_name` and `output_len` are no longer written (they read
 * payload fields CC never sends, so they were constant on 100% of rows), and
 * `model` now comes from the transcript rather than a `tool_input` that does
 * not exist at SubagentStop.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import type { HookInput } from '../../types.js';
import { mockCommonBasic } from '../fixtures/mock-common.js';

// Mocks are hoisted above the imports of the module under test — keep this
// ordering, it matches unified-dispatcher.test.ts.
vi.mock('../../lib/common.js', () => mockCommonBasic());
vi.mock('../../lib/session-tracker.js', () => ({ trackEvent: vi.fn() }));
vi.mock('../../lib/analytics.js', () => ({
  appendAnalytics: vi.fn(),
  hashProject: vi.fn(() => 'testpid000000'),
  getTeamContext: vi.fn(() => undefined),
}));
vi.mock('../../lib/agent-attribution.js', () => ({
  resolveAgentContext: vi.fn(() => ({ startMs: 0, counter: 0, commitBase: '', type: undefined })),
  appendLedgerEntry: vi.fn(),
}));
vi.mock('../../subagent-stop/handoff-preparer.js', () => ({ handoffPreparer: vi.fn(() => ({ continue: true })) }));
vi.mock('../../subagent-stop/feedback-loop.js', () => ({ feedbackLoop: vi.fn(() => ({ continue: true })) }));

import { mkdtempSync, rmSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { unifiedSubagentStopDispatcher } from '../../subagent-stop/unified-dispatcher.js';
import { appendAnalytics } from '../../lib/analytics.js';
import { trackEvent } from '../../lib/session-tracker.js';
import { resolveAgentContext } from '../../lib/agent-attribution.js';
import { createTestContext } from '../fixtures/test-context.js';

/** Last row written to agent-usage.jsonl, or undefined. */
function lastUsageRow(): Record<string, unknown> | undefined {
  const calls = vi.mocked(appendAnalytics).mock.calls.filter(c => c[0] === 'agent-usage.jsonl');
  return calls.length ? (calls[calls.length - 1][1] as Record<string, unknown>) : undefined;
}

describe('agent-usage row contract (#3034, #3035)', () => {
  let tmp: string;
  let ctx: ReturnType<typeof createTestContext>;

  const input = (o: Partial<HookInput> = {}): HookInput => ({
    tool_name: 'Task',
    session_id: 's1',
    project_dir: '/test/project',
    tool_input: {},
    agent_id: 'agent-1',
    ...o,
  }) as HookInput;

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'phantom-'));
    ctx = createTestContext();
    vi.clearAllMocks();
    // clearAllMocks does NOT restore implementations — re-assert the default so
    // a throwing mock from another file/test cannot leak in.
    vi.mocked(trackEvent).mockImplementation(() => undefined);
    vi.mocked(resolveAgentContext).mockReturnValue({ startMs: 0, counter: 0, commitBase: 'abc', type: undefined });
  });

  afterEach(() => {
    try { rmSync(tmp, { recursive: true, force: true }); } catch { /* best-effort */ }
  });

  /** Write a transcript containing one assistant line naming a model. */
  function seedTranscript(model = 'claude-opus-4-8'): string {
    const p = join(tmp, 'agent.jsonl');
    writeFileSync(p, `{"type":"assistant","message":{"model":"${model}","usage":{"input_tokens":10,"output_tokens":20}}}\n`);
    return p;
  }

  describe('#3035 phantom classification', () => {
    it('marks a stop with no type, no staged start and no transcript as phantom', async () => {
      await unifiedSubagentStopDispatcher(input(), ctx);
      expect(lastUsageRow()).toMatchObject({ agent: 'unknown', phantom: true, has_transcript: false });
    });

    it('suppresses the spawn event for a phantom — it never ran', async () => {
      await unifiedSubagentStopDispatcher(input(), ctx);
      expect(trackEvent).not.toHaveBeenCalledWith('agent_spawned', expect.anything(), expect.anything());
    });

    it('does NOT mark a typed agent as phantom even with no transcript', async () => {
      await unifiedSubagentStopDispatcher(input({ subagent_type: 'ork:test-generator' }), ctx);
      const row = lastUsageRow();
      expect(row).toMatchObject({ agent: 'ork:test-generator' });
      expect(row).not.toHaveProperty('phantom');
    });

    it('does NOT mark an untyped agent as phantom when a transcript exists', async () => {
      const row = await unifiedSubagentStopDispatcher(
        input({ agent_transcript_path: seedTranscript() }), ctx,
      ).then(lastUsageRow);
      expect(row).toMatchObject({ has_transcript: true });
      expect(row).not.toHaveProperty('phantom');
    });

    it('does NOT mark an untyped agent as phantom when a start was staged', async () => {
      vi.mocked(resolveAgentContext).mockReturnValue({
        startMs: Date.now() - 5000, counter: 0, commitBase: 'abc', type: undefined,
      });
      await unifiedSubagentStopDispatcher(input(), ctx);
      expect(lastUsageRow()).not.toHaveProperty('phantom');
    });

    it('writes has_transcript on every row, so its ABSENCE dates legacy rows', async () => {
      await unifiedSubagentStopDispatcher(input({ subagent_type: 'Explore' }), ctx);
      expect(lastUsageRow()).toHaveProperty('has_transcript');
    });
  });

  describe('#3034 field contract', () => {
    it('recovers model from the transcript', async () => {
      await unifiedSubagentStopDispatcher(
        input({ subagent_type: 'Explore', agent_transcript_path: seedTranscript('claude-fable-5') }), ctx,
      );
      expect(lastUsageRow()).toMatchObject({ model: 'claude-fable-5' });
    });

    it('writes model null rather than the literal "unknown" when unrecoverable', async () => {
      await unifiedSubagentStopDispatcher(input({ subagent_type: 'Explore' }), ctx);
      expect(lastUsageRow()).toMatchObject({ model: null });
    });

    it('no longer writes agent_name or output_len — a constant key reads as data', async () => {
      await unifiedSubagentStopDispatcher(
        input({ subagent_type: 'Explore', tool_input: { name: 'researcher' } }), ctx,
      );
      const row = lastUsageRow();
      expect(row).not.toHaveProperty('agent_name');
      expect(row).not.toHaveProperty('output_len');
    });

    it('derives duration from the staged start when CC omits duration_ms', async () => {
      vi.mocked(resolveAgentContext).mockReturnValue({
        startMs: Date.now() - 4000, counter: 0, commitBase: 'abc', type: 'Explore',
      });
      await unifiedSubagentStopDispatcher(input(), ctx);
      const row = lastUsageRow();
      expect(typeof row?.duration_ms).toBe('number');
      expect(row?.duration_ms as number).toBeGreaterThan(0);
    });
  });

  it('a throwing trackEvent must NOT cost us the analytics row', async () => {
    vi.mocked(trackEvent).mockImplementation(() => { throw new Error('profiling down'); });
    await unifiedSubagentStopDispatcher(input({ subagent_type: 'Explore' }), ctx);
    expect(lastUsageRow()).toMatchObject({ agent: 'Explore' });
  });
});
